PROMPT_EOF

# Append Entire context if available
if [ -n "$ENTIRE_CONTEXT" ]; then
  cat >> "$PROMPT_FILE" <<ENTIRE_EOF

ENTIRE CHECKPOINT CONTEXT (additional signal — use this for richer summaries):

